/// <summary>
/// This class ETGSalesParmLine_Table_Extension is created to implement the Modified field method for table fields
/// </summary>
[ExtensionOf(tableStr(SalesParmLine))]
final class ETGSalesParmLine_Table_Extension
{
}

Method.Source:
void ModifiedField(FieldId _fieldId)
{
    next ModifiedField(_fieldId);

    switch (_fieldId)
    {
        case fieldnum(SalesParmLine, ETGBillofLadingWeight):
            this.ETGWeightLoss         = this.ETGBillofLadingWeight - this.ETGPalletsLotWeight;
            this.ETGWeightLossPer      = this.ETGWeightLoss - this.ETGPalletsLotWeight;
            break;

        case fieldnum(SalesParmLine, ETGPalletsLotWeight):
            this.ETGWeightLoss         = this.ETGBillofLadingWeight - this.ETGPalletsLotWeight;
            this.ETGWeightLossPer      = this.ETGWeightLoss - this.ETGPalletsLotWeight;
            break;
        case fieldnum(SalesParmLine, ETGContractQuantity):
            this.ETGNumberofContainer         = this.ETGContractQuantity/25;

            break;
    }

}
